import React, { useEffect, useState } from "react";
import axios from "axios";
import { Line, Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  Title,
  Tooltip,
  Legend
);

export default function Reportes() {
  const [ventasDia, setVentasDia] = useState([]);
  const [ventasMes, setVentasMes] = useState([]);

  useEffect(() => {
    obtenerVentasDia();
    obtenerVentasMes();
  }, []);

  const obtenerVentasDia = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/reportes/ventas/dia");
      setVentasDia(res.data);
    } catch (error) {
      console.error("❌ Error ventas por día:", error);
    }
  };

  const obtenerVentasMes = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/reportes/ventas/mes");
      setVentasMes(res.data);
    } catch (error) {
      console.error("❌ Error ventas por mes:", error);
    }
  };

  /* =========================
     DATOS PARA GRÁFICAS
  ========================= */

  const dataDia = {
    labels: ventasDia.map(v => v.Fecha),
    datasets: [
      {
        label: "Ingresos diarios ($)",
        data: ventasDia.map(v => Number(v.TotalIngresos)),
        borderColor: "rgba(54,162,235,1)",
        backgroundColor: "rgba(54,162,235,0.3)",
        tension: 0.3,
        fill: true
      },
    ],
  };

  const dataMes = {
    labels: ventasMes.map(v => `${v.Mes}/${v.Año}`),
    datasets: [
      {
        label: "Ingresos mensuales ($)",
        data: ventasMes.map(v => Number(v.TotalIngresos)),
        backgroundColor: "rgba(153,102,255,0.6)",
      },
    ],
  };

  return (
    <div className="container mt-5">
      <h2 className="fw-bold mb-4">📊 Reportes de Ventas</h2>

      <div className="card shadow p-4 mb-5">
        <h5 className="mb-3">Ventas por Día</h5>
        <Line data={dataDia} />
      </div>

      <div className="card shadow p-4">
        <h5 className="mb-3">Ventas por Mes</h5>
        <Bar data={dataMes} />
      </div>
    </div>
  );
}
